* {
    margin: 0;
    padding: 0;
    box-sizing: border-box;
}

body {
    font-family: 'Arial', sans-serif;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    min-height: 100vh;
    display: flex;
    justify-content: center;
    align-items: center;
}

.container {
    background: white;
    border-radius: 12px;
    padding: 40px;
    box-shadow: 0 20px 60px rgba(0, 0, 0, 0.3);
    text-align: center;
}

h1 {
    color: #333;
    margin-bottom: 30px;
    font-size: 2.5em;
}

.game-info {
    margin-bottom: 30px;
    min-height: 60px;
    display: flex;
    flex-direction: column;
    justify-content: center;
    align-items: center;
}

.turn-indicator {
    font-size: 1.3em;
    color: #667eea;
    font-weight: bold;
    transition: opacity 0.3s ease;
}

.turn-indicator.hidden {
    display: none;
}

.winner-display {
    font-size: 1.5em;
    font-weight: bold;
    color: #28a745;
    padding: 10px 20px;
    background-color: #d4edda;
    border-radius: 8px;
    transition: all 0.3s ease;
}

.winner-display.hidden {
    display: none;
}

#current-player {
    color: #764ba2;
    font-size: 1.2em;
}

.board {
    display: grid;
    grid-template-columns: repeat(3, 100px);
    gap: 8px;
    margin-bottom: 30px;
    padding: 10px;
    background-color: #f5f5f5;
    border-radius: 8px;
}

.cell {
    width: 100px;
    height: 100px;
    background: white;
    border: 2px solid #ddd;
    border-radius: 8px;
    font-size: 2.5em;
    font-weight: bold;
    display: flex;
    justify-content: center;
    align-items: center;
    cursor: pointer;
    transition: all 0.2s ease;
    color: #333;
}

.cell:hover:not(.disabled) {
    background-color: #f0f0f0;
    border-color: #667eea;
    transform: scale(1.05);
}

.cell.disabled {
    cursor: not-allowed;
}

.cell.x {
    color: #667eea;
}

.cell.o {
    color: #764ba2;
}

.cell.winner {
    background-color: #fff3cd;
    border-color: #ffc107;
    box-shadow: 0 0 10px rgba(255, 193, 7, 0.5);
}

.reset-btn {
    padding: 12px 30px;
    font-size: 1.1em;
    font-weight: bold;
    color: white;
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    border: none;
    border-radius: 8px;
    cursor: pointer;
    transition: all 0.3s ease;
    box-shadow: 0 4px 15px rgba(102, 126, 234, 0.4);
}

.reset-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.6);
}

.reset-btn:active {
    transform: translateY(0);
}

