            this.winnerText = document.getElementById('winner-text');
            this.resetBtn = document.getElementById('reset-btn');
            this.attachEventListeners();
        }
    }

    attachEventListeners() {
        this.cells.forEach((cell, index) => {
            cell.addEventListener('click', () => this.handleCellClick(index));
        });
        this.resetBtn.addEventListener('click', () => this.resetGame());
    }

    handleCellClick(index) {
        // 게임 종료 상태이거나 이미 채워진 셀이면 반환
        if (this.gameOver || this.board[index] !== null) {
            return;
        }

        // 셀에 현재 플레이어 마크 추가
        this.board[index] = this.currentPlayer;
        this.updateCell(index);

        // 승자 확인
        const result = this.checkWinner();
        if (result.winner) {
            this.endGame(result.winner, result.pattern);
            return;
        }

        // 무승부 확인
        if (this.isBoardFull()) {
            this.endGame('draw');
            return;
        }

        // 플레이어 전환
        this.switchPlayer();
    }

    updateCell(index) {
        const cell = this.cells[index];
        cell.textContent = this.board[index];
        cell.classList.add(this.board[index].toLowerCase());
        cell.classList.add('disabled');
    }

    switchPlayer() {
        this.currentPlayer = this.currentPlayer === 'X' ? 'O' : 'X';
        this.currentPlayerSpan.textContent = this.currentPlayer;
    }

    checkWinner() {
        for (const pattern of this.winningPatterns) {
            const [a, b, c] = pattern;
            if (
                this.board[a] &&
                this.board[a] === this.board[b] &&
                this.board[a] === this.board[c]
            ) {
                return {
                    winner: this.board[a],
                    pattern: pattern
                };
            }
        }
        return { winner: null, pattern: null };
    }

    isBoardFull() {
        return this.board.every(cell => cell !== null);
    }

    endGame(result, pattern = null) {
        this.gameOver = true;
        this.turnIndicator.classList.add('hidden');

        if (result === 'draw') {
            this.winnerText.textContent = "It's a Draw!";
        } else {
            this.winnerText.textContent = `Player ${result} Wins!`;
            // 승리한 셀 하이라이트
            if (pattern) {
                pattern.forEach(index => {
                    this.cells[index].classList.add('winner');
                });
            }
        }

        this.winnerDisplay.classList.remove('hidden');
        // 모든 셀을 disabled 상태로 변경
        this.cells.forEach(cell => {
            cell.classList.add('disabled');
        });
    }

    resetGame() {
        this.board = Array(9).fill(null);
        this.currentPlayer = 'X';
        this.gameOver = false;
        this.winner = null;

        // UI 초기화
        this.cells.forEach(cell => {
            cell.textContent = '';
            cell.className = 'cell';
        });

        this.currentPlayerSpan.textContent = 'X';
        this.turnIndicator.classList.remove('hidden');
        this.winnerDisplay.classList.add('hidden');
        this.winnerText.textContent = '';
    }
}

// 게임 시작
document.addEventListener('DOMContentLoaded', () => {
    new TicTacToeGame();
});

