const TicTacToeGame = require('./game.js');

// 테스트 유틸리티
let testsPassed = 0;
let testsFailed = 0;

function assert(condition, message) {
    if (condition) {
        console.log(`✓ ${message}`);
        testsPassed++;
    } else {
        console.log(`✗ ${message}`);
        testsFailed++;
    }
}

function assertEquals(actual, expected, message) {
    const isEqual = JSON.stringify(actual) === JSON.stringify(expected);
    assert(isEqual, message);
    if (!isEqual) {
        console.log(`  Expected: ${JSON.stringify(expected)}`);
        console.log(`  Actual: ${JSON.stringify(actual)}`);
    }
}

// 테스트 그룹 시작/종료 출력
function describe(name, fn) {
    console.log(`\n📋 ${name}`);
    fn();
}

// ==================== 테스트 케이스 ====================

describe('Row Win Detection', () => {
    // 위쪽 행 승리 (0, 1, 2)
    const game1 = new TicTacToeGame(false);
    game1.board = ['X', 'X', 'X', null, null, null, null, null, null];
    const result1 = game1.checkWinner();
    assert(result1.winner === 'X', 'Should detect top row win for X');
    assertEquals(result1.pattern, [0, 1, 2], 'Should identify correct winning pattern');

    // 중간 행 승리 (3, 4, 5)
    const game2 = new TicTacToeGame(false);
    game2.board = [null, null, null, 'O', 'O', 'O', null, null, null];
    const result2 = game2.checkWinner();
    assert(result2.winner === 'O', 'Should detect middle row win for O');
    assertEquals(result2.pattern, [3, 4, 5], 'Should identify correct winning pattern');

    // 아래쪽 행 승리 (6, 7, 8)
    const game3 = new TicTacToeGame(false);
    game3.board = [null, null, null, null, null, null, 'X', 'X', 'X'];
    const result3 = game3.checkWinner();
    assert(result3.winner === 'X', 'Should detect bottom row win for X');
    assertEquals(result3.pattern, [6, 7, 8], 'Should identify correct winning pattern');
});

describe('Column Win Detection', () => {
    // 왼쪽 열 승리 (0, 3, 6)
    const game1 = new TicTacToeGame(false);
    game1.board = ['X', null, null, 'X', null, null, 'X', null, null];
    const result1 = game1.checkWinner();
    assert(result1.winner === 'X', 'Should detect left column win for X');
    assertEquals(result1.pattern, [0, 3, 6], 'Should identify correct winning pattern');

    // 중간 열 승리 (1, 4, 7)
    const game2 = new TicTacToeGame(false);
    game2.board = [null, 'O', null, null, 'O', null, null, 'O', null];
    const result2 = game2.checkWinner();
    assert(result2.winner === 'O', 'Should detect middle column win for O');
    assertEquals(result2.pattern, [1, 4, 7], 'Should identify correct winning pattern');

    // 오른쪽 열 승리 (2, 5, 8)
    const game3 = new TicTacToeGame(false);
    game3.board = [null, null, 'X', null, null, 'X', null, null, 'X'];
    const result3 = game3.checkWinner();
    assert(result3.winner === 'X', 'Should detect right column win for X');
    assertEquals(result3.pattern, [2, 5, 8], 'Should identify correct winning pattern');
});

describe('Diagonal Win Detection', () => {
    // 대각선 (0, 4, 8)
    const game1 = new TicTacToeGame(false);
    game1.board = ['X', null, null, null, 'X', null, null, null, 'X'];
    const result1 = game1.checkWinner();
    assert(result1.winner === 'X', 'Should detect top-left to bottom-right diagonal win for X');
    assertEquals(result1.pattern, [0, 4, 8], 'Should identify correct winning pattern');

    // 대각선 (2, 4, 6)
    const game2 = new TicTacToeGame(false);
    game2.board = [null, null, 'O', null, 'O', null, 'O', null, null];
    const result2 = game2.checkWinner();
    assert(result2.winner === 'O', 'Should detect top-right to bottom-left diagonal win for O');
    assertEquals(result2.pattern, [2, 4, 6], 'Should identify correct winning pattern');
});

describe('Draw Detection', () => {
    // 무승부 상황
    const game = new TicTacToeGame(false);
    game.board = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', 'X'];
    assert(game.isBoardFull(), 'Should detect full board');
    const result = game.checkWinner();
    assert(result.winner === null, 'Should have no winner');
    assert(game.isBoardFull() && result.winner === null, 'Should correctly identify draw');
});

describe('Turn Switching', () => {
    const game = new TicTacToeGame(false);
    assert(game.currentPlayer === 'X', 'Initial player should be X');

    game.board[0] = 'X';
    game.currentPlayer = 'O'; // simulate switchPlayer
    assert(game.currentPlayer === 'O', 'After first move, current player should be O');

    game.board[1] = 'O';
    game.currentPlayer = 'X'; // simulate switchPlayer
    assert(game.currentPlayer === 'X', 'After second move, current player should be X');
});

describe('Reset Functionality', () => {
    const game = new TicTacToeGame(false);

    // 게임 진행
    game.board = ['X', 'O', 'X', 'X', 'O', 'O', 'O', 'X', 'X'];
    game.currentPlayer = 'O';
    game.gameOver = true;
    game.winner = 'O';

    // 리셋
    game.board = Array(9).fill(null);
    game.currentPlayer = 'X';
    game.gameOver = false;
    game.winner = null;

    assert(game.board.every(cell => cell === null), 'Board should be empty after reset');
    assert(game.currentPlayer === 'X', 'Current player should be X after reset');
    assert(game.gameOver === false, 'Game should not be over after reset');
    assert(game.winner === null, 'Winner should be null after reset');
});

describe('No Winner Detection', () => {
    const game = new TicTacToeGame(false);
    game.board = ['X', 'O', null, 'X', 'O', null, null, null, null];
    const result = game.checkWinner();
    assert(result.winner === null, 'Should return null when no winner exists');
});

describe('Move Validation', () => {
    const game = new TicTacToeGame(false);
    game.board[0] = 'X';

    // 이미 채워진 셀에는 둘 수 없음 (게임 로직에서 처리)
    assert(game.board[0] === 'X', 'Cell should contain X');
    assert(game.board[1] === null, 'Empty cell should remain null');
});

